module top_module(
  input clk_in,
  input reset,
  output reg clk_out
);parameter divide_by = 2;

reg [31:0] unused_counter;

always @(posedge clk_in or posedge reset) begin
  if (reset) begin
    clk_out <= 1'b0;
    unused_counter <= 0;
  end
  else begin
    if (unused_counter == divide_by - 1) begin
      clk_out <= ~clk_out;
      unused_counter <= 0;
    end
    else begin
      unused_counter <= unused_counter + 1;
    end
  end
end

endmodule
